#include<bits/stdc++.h>
using namespace std;
int a[105][105];
int n,m;
int dx[8]={1,1, 1,-1,-1,-1, 0, 0};
int dy[8]={1,0,-1, 1, 0,-1, 1,-1};
bool b[105][105];
void dfs(int x,int y){
    for(int i=0;i<8;i++){
        if(b[dx[i]+x][dy[i]+y]){
            a[x][y]++;
        }
    }
}
int main(){
    cin>>n>>m;
    for(int i=1;i<=n;i++){
        for(int j=1;j<=m;j++){
            char c;
            cin>>c;
            if(c=='*'){
                b[i][j]=1;
            }
        }
    }
    for(int i=1;i<=n;i++){
        for(int j=1;j<=m;j++){
            if(b[i][j]==0) dfs(i,j);
        }
    }
    for(int i=1;i<=n;i++){
        for(int j=1;j<=m;j++){
            if(b[i][j]==1){
                cout<<"*";
            }else{
                cout<<a[i][j];
            }
        }
        cout<<"\n";
    }
    return 0;
}
